local LxStateActor = classX("LxStateActor", nil)

local typeofYXUIStateActor = typeof(CS.YXUIStateActor)

function LxStateActor:LxStateActor(stateActor)

    self._stateActor = stateActor


    ---@type string[]
    self._spritePaths = {}
    self._spriteIndexs = {}
end

function LxStateActor:Dispose()
    for k,v in pairs(self._spritePaths) do
        MgrCenter.ComponentMgr:RecycleSprite(v)
    end
    table.dispose(self)
    self._isDisposed = true
end

function LxStateActor:InitLang()
    local stateActor = self._stateActor
    if gLGameLanguage:IsForeignVersion() then
        local stateSprite = nil
        local spriteResName = nil
        local langResName = nil
        local isNativeSize = nil
        local cnt = stateActor.m_stateList.Count
        for i = 1,cnt  do
            stateSprite = stateActor.m_stateList[i-1]
            if CS.IsValidObject(stateSprite) then
                spriteResName = stateSprite.name
                langResName,isNativeSize = LGameLanguage:GetResName(spriteResName)
                if spriteResName ~= langResName then
                    MgrCenter.ComponentMgr:RequestSprite(spriteResName, function(sprite, requestPath)
                        if self._isDisposed then return false end
                        self._spritePaths[requestPath] = requestPath
                        stateActor.m_stateList[i-1] = sprite
                        return true
                    end)
                end
            end
        end
    end
end

function LxStateActor:SetImageActorState(state)
    local stateActor = self._stateActor
    stateActor:SetState(state)
end


